
.tab-nav {
  display: flex;
  border-bottom: 1px solid var(--c-border);
  background: var(--c-deep);
}

.tab-btn {
  flex: 1;
  padding: 7px 0;
  border: none;
  background: transparent;
  color: var(--c-text2);
  font-size: 0.8rem;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.2s;
  border-bottom: 2px solid transparent;

  &:hover {
    color: var(--c-text);
  }

  &.active {
    color: var(--c-accent);
    border-bottom-color: var(--c-accent);
  }
}
