
.milestone-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.section-desc {
  font-size: 0.72rem;
  color: var(--c-text2);
  font-style: italic;
  line-height: 1.4;
}

.milestone-list {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.milestone-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 8px;
  border: 1px solid var(--c-border);
  border-radius: 4px;
  background: var(--c-deep);
  cursor: pointer;
  transition: all 0.15s;

  &:hover {
    border-color: var(--c-accent3);
  }

  &.locked {
    .ms-checkbox:not(:checked) {
      + .ms-name {
        color: var(--c-text2);
      }
    }
  }
}

.ms-checkbox {
  appearance: none;
  width: 16px;
  height: 16px;
  border: 2px solid var(--c-border);
  border-radius: 3px;
  background: var(--c-surface);
  display: grid;
  place-content: center;
  flex-shrink: 0;
  cursor: pointer;

  &::before {
    content: '';
    width: 8px;
    height: 8px;
    border-radius: 1px;
    transform: scale(0);
    transition: transform 0.12s ease;
    background: var(--c-accent);
  }

  &:checked::before {
    transform: scale(1);
  }

  &:checked {
    border-color: var(--c-accent);
  }
}

.ms-name {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--c-text);
  min-width: 80px;
}

.ms-desc {
  font-size: 0.7rem;
  color: var(--c-text2);
  flex: 1;
}

.reset-section {
  display: flex;
  justify-content: flex-end;
  padding-top: 4px;
}

.reset-btn {
  padding: 4px 12px;
  border: 1px solid var(--c-border);
  border-radius: 4px;
  background: var(--c-surface);
  color: var(--c-text2);
  font-size: 0.72rem;
  font-family: inherit;
  cursor: pointer;

  &:hover {
    border-color: var(--c-danger);
    color: var(--c-danger);
  }
}
