
.char-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.char-card {
  border: 1.5px solid var(--c-border);
  border-radius: 6px;
  padding: 8px 10px;
  background: var(--c-deep);
}

.char-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 6px;
}

.char-name {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--c-text);
}

.char-stage {
  font-size: 0.68rem;
  padding: 1px 6px;
  border-radius: 3px;
  font-weight: 500;

  &.stage-alice { background: rgba(233, 69, 96, 0.15); color: var(--c-accent); }
  &.stage-snow { background: rgba(0, 180, 216, 0.15); color: var(--c-accent3); }
  &.stage-rose { background: rgba(240, 165, 0, 0.15); color: var(--c-accent2); }
  &.stage-grimm { background: rgba(155, 89, 182, 0.15); color: #9b59b6; }
  &.stage-heine { background: rgba(46, 204, 113, 0.15); color: var(--c-success); }
  &.stage-tungsten { background: rgba(241, 196, 15, 0.15); color: #f1c40f; }
}

.affinity-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.aff-label {
  font-size: 0.65rem;
  color: var(--c-text2);
  text-transform: uppercase;
  width: 36px;
}

.aff-track {
  flex: 1;
  height: 6px;
  border-radius: 3px;
  background: var(--c-border);
  overflow: hidden;
}

.aff-fill {
  height: 100%;
  border-radius: 3px;
  background: linear-gradient(90deg, var(--c-accent), var(--c-accent2));
  transition: width 0.3s ease;
}

.aff-value {
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--c-accent2);
  min-width: 24px;
  text-align: center;
}

.aff-btns {
  display: flex;
  gap: 2px;
}

.aff-btn {
  padding: 1px 5px;
  border: 1px solid var(--c-border);
  border-radius: 3px;
  background: var(--c-surface);
  color: var(--c-text2);
  font-size: 0.65rem;
  font-family: inherit;
  cursor: pointer;

  &:hover {
    border-color: var(--c-accent3);
    color: var(--c-text);
  }
}

.char-detail {
  margin-top: 4px;
  font-size: 0.7rem;
  color: var(--c-text2);
  font-style: italic;
}
